import{_ as t,c as a,o,a1 as s}from"./chunks/framework.DDNAyvCW.js";const i="/assets/hosts.C4ZoDOIh.png",p=JSON.parse('{"title":"Host List Operations","description":"","frontmatter":{},"headers":[],"relativePath":"docs/hosts/index.md","filePath":"docs/hosts/index.md"}'),n={name:"docs/hosts/index.md"};function r(c,e,h,d,l,u){return o(),a("div",null,e[0]||(e[0]=[s('<h1 id="host-list-operations" tabindex="-1">Host List Operations <a class="header-anchor" href="#host-list-operations" aria-label="Permalink to &quot;Host List Operations&quot;">​</a></h1><h2 id="host-list" tabindex="-1">Host List <a class="header-anchor" href="#host-list" aria-label="Permalink to &quot;Host List&quot;">​</a></h2><p><img src="'+i+'" alt=""></p><p>The host list module is used to manage the list of hosts added by users. From the left navigation menu, go to <strong>Hosts</strong>. By default, the system shows the direct‑connection host list. To view bastion assets, switch to the <strong>Bastion Resources</strong> list.</p><h2 id="search" tabindex="-1">Search <a class="header-anchor" href="#search" aria-label="Permalink to &quot;Search&quot;">​</a></h2><p>In the host list, use the search box to quickly find hosts by IP address or alias. Matching hosts are filtered and displayed in real time.</p><h2 id="favorites" tabindex="-1">Favorites <a class="header-anchor" href="#favorites" aria-label="Permalink to &quot;Favorites&quot;">​</a></h2><p>In the host list, open a host context menu to add the host to Favorites or remove it from Favorites, making it easy to quickly access frequently used hosts.</p><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h3 id="organize-hosts-into-groups" tabindex="-1">Organize hosts into groups <a class="header-anchor" href="#organize-hosts-into-groups" aria-label="Permalink to &quot;Organize hosts into groups&quot;">​</a></h3><p>Group hosts by project, environment, or purpose to improve management efficiency and discovery. Common examples:</p><ul><li><code>Development</code></li><li><code>Testing</code></li><li><code>Production</code></li><li><code>Database servers</code></li><li><code>Web servers</code></li></ul><h3 id="secure-authentication" tabindex="-1">Secure authentication <a class="header-anchor" href="#secure-authentication" aria-label="Permalink to &quot;Secure authentication&quot;">​</a></h3><p>Prefer SSH key-based authentication to improve connection security. For details on key management, see the <a href="/docs/manage/keys/">Key Management</a> documentation.</p><h3 id="detailed-notes" tabindex="-1">Detailed notes <a class="header-anchor" href="#detailed-notes" aria-label="Permalink to &quot;Detailed notes&quot;">​</a></h3><p>Add clear notes to hosts to record important configuration parameters and usage instructions so team members can quickly understand and use them.</p><h3 id="regular-maintenance" tabindex="-1">Regular maintenance <a class="header-anchor" href="#regular-maintenance" aria-label="Permalink to &quot;Regular maintenance&quot;">​</a></h3><p>Regularly review and update host configurations to ensure connection information is accurate and valid, and clean up hosts that are no longer in use in a timely manner.</p>',18)]))}const g=t(n,[["render",r]]);export{p as __pageData,g as default};
